const express = require('express');
const bodyParser = require('body-parser');
const xml2js = require('xml2js');
const fs = require('fs');
const app = express();
app.use(bodyParser.text({ type: 'application/xml' }));

app.post('/parseXML', (req, res) => {
  const parser = new xml2js.Parser();
  
  // If the uploaded XML has external schema references, we need to pass those into parseStringWithPrefixes function via localOptions argument
  let opts = {
    trim: true,
    explicitArray: false,
    mergeAttrs: true
  };

  parser.parseString(req.body, opts, (err, result) => {
    if (err) {
      res.status(500).send({ error: 'Failed to parse XML' });
    } else {
      res.json(result);
    }
  });
});

app.listen(3000, () => console.log('Server running on port 3000'));